{ Launch Interceptor Program — DECIDE and REALCOMPARE (K&L / spec.md) }

unit lipdecide;

interface

uses
  globals, math;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

const
  TINY: real = 1e-100;

function SqrD(x: real): real;
begin
  Result := x * x;
end;

function RDist2(const x1, y1, x2, y2: real): real;
begin
  Result := sqrt(SqrD(x1 - x2) + SqrD(y1 - y2));
end;

{ Each operand rounded to 6 significant decimal digits, then ordinally compared. }
function Round6Sig(x: real): real;
var
  ax: real;
  ei: integer;
  m: int64;
begin
  ax := abs(x);
  if ax < TINY then
    Result := 0
  else
  begin
    ei := floor(log10(ax));
    m := round(x * intpower(10, 5 - ei));
    Result := m * intpower(10, ei - 5);
  end;
end;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  ra, rb: real;
begin
  ra := Round6Sig(A);
  rb := Round6Sig(B);
  if ra < rb then
    Result := LT
  else if ra > rb then
    Result := GT
  else
    Result := EQ;
end;

{ Quadrant index 1..4; axis and origin tie-breaks per spec. }
function QuadrantOf(const x, y: real): integer;
begin
  if (REALCOMPARE(x, 0) = EQ) and (REALCOMPARE(y, 0) = EQ) then
    Result := 1
  else if (REALCOMPARE(y, 0) = EQ) then
  begin
    if REALCOMPARE(x, 0) = LT then
      Result := 2
    else
      Result := 1
  end
  else if (REALCOMPARE(x, 0) = EQ) then
  begin
    if REALCOMPARE(y, 0) = GT then
      Result := 1
    else
      Result := 3
  end
  else if (REALCOMPARE(x, 0) = GT) and (REALCOMPARE(y, 0) = GT) then
    Result := 1
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) = GT) then
    Result := 2
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) = LT) then
    Result := 3
  else
    Result := 4;
end;

{ Smallest circumcircle radius for three planar points. }
function MinEnclosingRadius3(
  const x1, y1, x2, y2, x3, y3: real): real;
var
  d12, d23, d13: real;
  ar: real;
  d12_2, d13_2, d23_2: real;
  obt1, obt2, obt3: boolean;
  mx: real;
begin
  d12 := RDist2(x1, y1, x2, y2);
  d13 := RDist2(x1, y1, x3, y3);
  d23 := RDist2(x2, y2, x3, y3);
  d12_2 := d12 * d12;
  d13_2 := d13 * d13;
  d23_2 := d23 * d23;
  ar := 0.5 * abs(
    x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
  { obtuse at each vertex: opposite side is longest; Law of cos }
  obt1 := (REALCOMPARE(d23_2, d12_2 + d13_2) = GT);
  obt2 := (REALCOMPARE(d13_2, d12_2 + d23_2) = GT);
  obt3 := (REALCOMPARE(d12_2, d13_2 + d23_2) = GT);
  if obt1 or obt2 or obt3 then
  begin
    mx := d12;
    if REALCOMPARE(d13, mx) = GT then
      mx := d13;
    if REALCOMPARE(d23, mx) = GT then
      mx := d23;
    Result := 0.5 * mx;
  end
  else if REALCOMPARE(ar, 0) = EQ then
  begin
    mx := d12;
    if REALCOMPARE(d13, mx) = GT then
      mx := d13;
    if REALCOMPARE(d23, mx) = GT then
      mx := d23;
    Result := 0.5 * mx;
  end
  else
    Result := (d12 * d13 * d23) / (4.0 * ar);
end;

function CannotFitInCircle3(
  const x1, y1, x2, y2, x3, y3, r: real): boolean;
var
  mr: real;
begin
  mr := MinEnclosingRadius3(x1, y1, x2, y2, x3, y3);
  Result := (REALCOMPARE(mr, r) = GT);
end;

function CanFitInCircle3(
  const x1, y1, x2, y2, x3, y3, r: real): boolean;
var
  mr: real;
begin
  mr := MinEnclosingRadius3(x1, y1, x2, y2, x3, y3);
  Result := (REALCOMPARE(mr, r) = LT) or (REALCOMPARE(mr, r) = EQ);
end;

{ Angle at (vx,vy) between (ax,ay) and (bx,by); false if undefined }
function AngleAtVertex(
  const ax, ay, vx, vy, bx, by: real;
  out ang: real): boolean;
var
  ux, uy, wx, wy: real;
  nu, nw, d: real;
  c: real;
begin
  ux := ax - vx;
  uy := ay - vy;
  wx := bx - vx;
  wy := by - vy;
  nu := sqrt(ux * ux + uy * uy);
  nw := sqrt(wx * wx + wy * wy);
  if (REALCOMPARE(nu, 0) = EQ) or (REALCOMPARE(nw, 0) = EQ) then
  begin
    Result := false;
    exit;
  end;
  d := ux * wx + uy * wy;
  c := d / (nu * nw);
  if c < -1.0 then
    c := -1.0
  else if c > 1.0 then
    c := 1.0;
  ang := arccos(c);
  Result := true;
end;

function Lic3AngleDeviates(
  const x1, y1, x2, y2, x3, y3, eps: real): boolean;
var
  a, lo, hi: real;
begin
  if not AngleAtVertex(x1, y1, x2, y2, x3, y3, a) then
  begin
    Result := false;
    exit;
  end;
  lo := PI - eps;
  hi := PI + eps;
  { spec: angle < (PI-EPS) or angle > (PI+EPS) }
  Result :=
    (REALCOMPARE(a, lo) = LT) or (REALCOMPARE(a, hi) = GT);
end;

function TriangleArea2(
  const x1, y1, x2, y2, x3, y3: real): real;
begin
  Result := 0.5 * abs(
    x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
end;

{ Point to infinite line (a,b) through (x1,y1)-(x2,y2); 0 if degenerate. }
function PointLineDist(
  const px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, t: real;
  len2: real;
  projx, projy: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  len2 := dx * dx + dy * dy;
  if REALCOMPARE(len2, 0) = EQ then
  begin
    Result := RDist2(px, py, x1, y1);
    exit;
  end;
  t := ((px - x1) * dx + (py - y1) * dy) / len2;
  projx := x1 + t * dx;
  projy := y1 + t * dy;
  Result := RDist2(px, py, projx, projy);
end;

function EvalCMV1: boolean;
var
  i: integer;
  d: real;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := RDist2(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV2: boolean;
var
  i: integer;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if CannotFitInCircle3(
      X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], PARAMETERS.RADIUS1) then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV3: boolean;
var
  i: integer;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if Lic3AngleDeviates(
      X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], PARAMETERS.EPSILON) then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV4: boolean;
var
  i: integer;
  a2: real;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    a2 := TriangleArea2(
      X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(a2, PARAMETERS.AREA1) = GT then
    begin
      Result := true;
      break;
    end;
  end;
end;

function CountDistinctQuadsInWindow(const start, qlen: integer): integer;
var
  seen: array[1..4] of boolean;
  j, k, q, c: integer;
begin
  for k := 1 to 4 do
    seen[k] := false;
  for j := 0 to qlen - 1 do
  begin
    q := QuadrantOf(X[start + j], Y[start + j]);
    seen[q] := true;
  end;
  c := 0;
  for k := 1 to 4 do
    if seen[k] then
      Inc(c);
  Result := c;
end;

function EvalCMV5: boolean;
var
  i, nq, maxStart: integer;
begin
  Result := false;
  maxStart := NUMPOINTS - PARAMETERS.Q_PTS + 1;
  for i := 1 to maxStart do
  begin
    nq := CountDistinctQuadsInWindow(i, PARAMETERS.Q_PTS);
    if nq > PARAMETERS.QUADS then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV6: boolean;
var
  i: integer;
begin
  Result := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV7: boolean;
var
  s, t: integer;
  d: real;
  firstEqLast: boolean;
  any: boolean;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  for s := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    firstEqLast :=
      (REALCOMPARE(X[s], X[s + PARAMETERS.N_PTS - 1]) = EQ) and
      (REALCOMPARE(Y[s], Y[s + PARAMETERS.N_PTS - 1]) = EQ);
    any := false;
    if firstEqLast then
    begin
      for t := 0 to PARAMETERS.N_PTS - 1 do
      begin
        d := RDist2(
          X[s + t], Y[s + t], X[s], Y[s]);
        if REALCOMPARE(d, PARAMETERS.DIST) = GT then
        begin
          any := true;
          break;
        end;
      end;
    end
    else
    begin
      for t := 0 to PARAMETERS.N_PTS - 1 do
      begin
        d := PointLineDist(
          X[s + t], Y[s + t],
          X[s], Y[s], X[s + PARAMETERS.N_PTS - 1], Y[s + PARAMETERS.N_PTS - 1]);
        if REALCOMPARE(d, PARAMETERS.DIST) = GT then
        begin
          any := true;
          break;
        end;
      end;
    end;
    if any then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV8: boolean;
var
  i, j: integer;
  d: real;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := RDist2(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV9: boolean;
var
  i: integer;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if CannotFitInCircle3(
      X[i], Y[i],
      X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
      PARAMETERS.RADIUS1) then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV10: boolean;
var
  i: integer;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    if Lic3AngleDeviates(
      X[i], Y[i],
      X[i + PARAMETERS.C_PTS + 1], Y[i + PARAMETERS.C_PTS + 1],
      X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2], Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2],
      PARAMETERS.EPSILON) then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV11: boolean;
var
  i: integer;
  a2: real;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    a2 := TriangleArea2(
      X[i], Y[i],
      X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
      X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
    if REALCOMPARE(a2, PARAMETERS.AREA1) = GT then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV12: boolean;
var
  i, j: integer;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0) = LT then
    begin
      Result := true;
      break;
    end;
  end;
end;

function EvalCMV13: boolean;
var
  i, j: integer;
  d: real;
  gtl, ltl: boolean;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit;
  gtl := false;
  ltl := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := RDist2(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      gtl := true;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      ltl := true;
    if gtl and ltl then
      break;
  end;
  Result := gtl and ltl;
end;

function EvalCMV14: boolean;
var
  i: integer;
  r1, r2: boolean;
  x1, y1, x2, y2, x3, y3: real;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;
  r1 := false;
  r2 := false;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    x1 := X[i];
    y1 := Y[i];
    x2 := X[i + PARAMETERS.A_PTS + 1];
    y2 := Y[i + PARAMETERS.A_PTS + 1];
    x3 := X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2];
    y3 := Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2];
    if not r1 and CannotFitInCircle3(
      x1, y1, x2, y2, x3, y3, PARAMETERS.RADIUS1) then
      r1 := true;
    if not r2 and CanFitInCircle3(
      x1, y1, x2, y2, x3, y3, PARAMETERS.RADIUS2) then
      r2 := true;
    if r1 and r2 then
      break;
  end;
  Result := r1 and r2;
end;

function EvalCMV15: boolean;
var
  i: integer;
  a2: real;
  gtA, ltA2: boolean;
  x1, y1, x2, y2, x3, y3: real;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit;
  gtA := false;
  ltA2 := false;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    x1 := X[i];
    y1 := Y[i];
    x2 := X[i + PARAMETERS.E_PTS + 1];
    y2 := Y[i + PARAMETERS.E_PTS + 1];
    x3 := X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2];
    y3 := Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2];
    a2 := TriangleArea2(x1, y1, x2, y2, x3, y3);
    if not gtA and (REALCOMPARE(a2, PARAMETERS.AREA1) = GT) then
      gtA := true;
    if not ltA2 and (REALCOMPARE(a2, PARAMETERS.AREA2) = LT) then
      ltA2 := true;
    if gtA and ltA2 then
      break;
  end;
  Result := gtA and ltA2;
end;

procedure BuildPUMOffDiagonal;
var
  i, j: integer;
  v: boolean;
begin
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        continue;
      case LCM[i, j] of
        NOTUSED:
          v := true;
        ANDD:
          v := CMV[i] and CMV[j];
        ORR:
          v := CMV[i] or CMV[j];
        else
          v := true;
      end;
      PUM[i, j] := v;
    end;
end;

procedure BuildFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := true;
      continue;
    end;
    allTrue := true;
    for j := 1 to 15 do
    begin
      if not PUM[i, j] then
      begin
        allTrue := false;
        break;
      end;
    end;
    FUV[i] := allTrue;
  end;
end;

procedure SetLaunch;
var
  i: integer;
  ok: boolean;
begin
  ok := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      ok := false;
      break;
    end;
  LAUNCH := ok;
end;

procedure DECIDE;
begin
  CMV[1] := EvalCMV1;
  CMV[2] := EvalCMV2;
  CMV[3] := EvalCMV3;
  CMV[4] := EvalCMV4;
  CMV[5] := EvalCMV5;
  CMV[6] := EvalCMV6;
  CMV[7] := EvalCMV7;
  CMV[8] := EvalCMV8;
  CMV[9] := EvalCMV9;
  CMV[10] := EvalCMV10;
  CMV[11] := EvalCMV11;
  CMV[12] := EvalCMV12;
  CMV[13] := EvalCMV13;
  CMV[14] := EvalCMV14;
  CMV[15] := EvalCMV15;
  BuildPUMOffDiagonal;
  BuildFUV;
  SetLaunch;
end;

end.
